var input = $json;

const novoDialogo = {
  createdAt : DateTime.now(),
  usuario: input.msg.incomingMessage,
  agente: input.respostaIA.userMessage
};


let actionDataContext = input.pessoa.contexto_memoria.actionDataContext;
let newActionDataContext = input.respostaIA.actionDataContext;
newActionDataContext.faseCore = input.respostaIA.nextState;

if (newActionDataContext._RESET_CONTEXT) {
  newActionDataContext = {faseCore : newActionDataContext.faseCore};
} else {
  newActionDataContext = {...actionDataContext, ...newActionDataContext };  
}



input.pessoa.contexto_memoria.conversas_recentes.push(novoDialogo);
input.pessoa.contexto_memoria.actionDataContext = newActionDataContext;


